use std::time::Instant;

/// HELIX gate strategy enum.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum GateStrategy {
    /// Gates disabled entirely (baseline, no admission control).
    Disabled,
    /// Adaptive (default, recommended): dual-threshold gating.
    /// Gates enable at Re≥32 (helps p99 -45–63%) but disable at Re≥1024 (gate overhead +18–351%).
    /// Sweet zone: Re=32–512 where staggered admission prevents queue collapse.
    Adaptive,
    /// Gates always enabled (for testing/debugging).
    Aggressive,
}

/// Lean theorem ID the CERTIFIED admission decision realizes — a cert in hand is
/// always decided RED/GREEN, never the YELLOW probe.
/// Mirrors `gnosis_frf::value_door::VALUE_DOOR_CERTIFIED_THEOREM_ID`.
pub const HELIX_CERTIFIED_GATE_THEOREM_ID: &str =
    "Gnosis.ValueDoorStoplight.certified_never_yellow";

/// CERTIFIED admission — decide on the agent's cert-attested per-step COST, not
/// its position in the batch (`index`).
///
/// The `Adaptive` strategy above gates on `index` — a COUNT/SIZE axis (the
/// Re=32..1024 sweet-zone window). That is the wrong axis for the same reason
/// `gnosis_frf::value_door` found BATCH SIZE wrong: size cannot tell a cheap
/// agent (whose staggered spin-wait is pure drag) from a heavy one (whose stagger
/// pays by draining the reduce pile-up). Only per-item COST can. And because in
/// the chaos swarm nothing steps un-admitted, the per-agent cost is already known
/// from its node-op cert — there is no YELLOW probe to run.
///
/// `certified_step_cost` is the agent's cert-attested per-step work cost (e.g. the
/// node-op difficulty + edge cost, in the cost-algebra's score units / ns).
/// `coordination_cost` is the platform's per-agent staggering/contention cost.
/// GREEN (gate on, stagger): cost beats coordination — the corridor pays.
/// RED (gate off, admit immediately): cheap step — staggering is drag, skip it.
///
/// This decides each agent independently with zero cold-start and zero lag: a
/// heavy agent that lands at a low index is still gated; a cheap agent at a high
/// index is still admitted free. The `index`-window heuristic could do neither.
/// Returns `true` when the agent is admitted to step THIS instant; the GREEN
/// (gated) branch additionally requires the HELIX time-corridor to have opened.
pub fn admit_certified(
    batch_start: Instant,
    index: u64,
    service_time_us: u64,
    certified_step_cost: u64,
    coordination_cost: u64,
) -> bool {
    if foil_naive_enabled() {
        return true;
    }
    // value-door crossover on COST, not on `index`. `certified_never_yellow`:
    // the cert makes the probe state vacuous, so this is total RED/GREEN.
    match gnosis_frf::value_door::certified_light(certified_step_cost, coordination_cost) {
        // RED: cheap step — staggering is pure drag. Admit immediately (the fast
        // lane), regardless of how high the index is.
        gnosis_frf::value_door::Light::Red => true,
        // GREEN: heavy step — the corridor pays. Stagger by the HELIX time gate.
        gnosis_frf::value_door::Light::Green => {
            admit_helix(batch_start, index, service_time_us)
        }
        // Vacuous under a cert — `certified_light` never returns Yellow.
        gnosis_frf::value_door::Light::Yellow => true,
    }
}

impl GateStrategy {
    /// Parse strategy from env var HELIX_GATE_STRATEGY.
    /// Default: Adaptive (smart, hotpath-optimized).
    pub fn from_env() -> Self {
        match std::env::var("HELIX_GATE_STRATEGY").as_deref() {
            Ok("disabled") | Ok("0") => GateStrategy::Disabled,
            Ok("adaptive") | Ok("auto") | Err(_) => GateStrategy::Adaptive, // default
            Ok("aggressive") | Ok("1") => GateStrategy::Aggressive,
            _ => GateStrategy::Adaptive,
        }
    }
}

/// Check if FOIL_NAIVE env var is set (opts out of HELIX admission, baseline mode).
pub fn foil_naive_enabled() -> bool {
    std::env::var("FOIL_NAIVE").is_ok()
}

/// Main admission dispatcher with hotpath-first defaults.
///
/// Strategy precedence:
/// 1. If FOIL_NAIVE=1, always admit (baseline comparison)
/// 2. Otherwise check HELIX_GATE_STRATEGY env var (default: Adaptive)
///    - Disabled: never gate (hotpath, serial resident loops)
///    - Aggressive: always gate (testing, concurrent scenarios)
///    - Adaptive: dual-threshold gating (gates help at Re=32–512, hurt at Re>1024)
///
/// Adaptive mode measured results (monster-helix-ramp.mjs, 2026-05-17):
/// - Re < 32: No gates (hotpath unaffected, ~0% change)
/// - Re = 32–512: Gates ON (p99 improved -45% to -63%)
/// - Re >= 1024: Gates OFF (gate overhead +18% to +351%, kill the gates)
///
/// Resident loops are inherently serial (stdin-based), so gates add pure overhead.
/// Enable gates only in truly concurrent contexts (chaos engine, etc).
pub fn admit(batch_start: Instant, index: u64, service_time_us: u64) -> bool {
    if foil_naive_enabled() {
        return true;
    }

    let strategy = GateStrategy::from_env();
    match strategy {
        GateStrategy::Disabled => true,                                            // hotpath: default
        GateStrategy::Aggressive => admit_helix(batch_start, index, service_time_us), // testing
        GateStrategy::Adaptive => {
            // Dual-threshold: gates help at moderate concurrency (Re=32–512),
            // but hurt at extreme concurrency (Re>=1024). Hotpath at low Re.
            if index >= 32 && index < 1024 {
                admit_helix(batch_start, index, service_time_us)
            } else {
                true  // Hotpath: no gates outside sweet zone
            }
        }
    }
}

/// HELIX-path admission: stagger entry by service time.
/// Only called when gates are active.
pub fn admit_helix(batch_start: Instant, index: u64, service_time_us: u64) -> bool {
    // Calculate elapsed time since batch start.
    let elapsed_us = batch_start.elapsed().as_micros() as u64;

    // Expected admission time for this index: index * service_time_us.
    let expected_admission_us = index.saturating_mul(service_time_us);

    // Admit when clock catches up to expected time.
    elapsed_us >= expected_admission_us
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::thread;
    use std::time::Duration;

    #[test]
    fn test_foil_naive_disabled_by_default() {
        assert_eq!(std::env::var("FOIL_NAIVE").is_err(), !foil_naive_enabled());
    }

    #[test]
    fn test_gate_strategy_enum() {
        // Test strategy parsing (just check the enum exists and has right variants).
        assert_eq!(GateStrategy::Adaptive, GateStrategy::Adaptive);
        assert_ne!(GateStrategy::Adaptive, GateStrategy::Disabled);
        assert_ne!(GateStrategy::Aggressive, GateStrategy::Disabled);
    }

    #[test]
    fn test_admit_hotpath_low_index() {
        let batch_start = Instant::now();
        // Low index (< 32): hotpath, always admit regardless of strategy.
        assert!(admit(batch_start, 0, 5));
        assert!(admit(batch_start, 31, 5));
    }

    #[test]
    fn test_admit_helix_stagger_high_index() {
        let batch_start = Instant::now();
        // Moderate index (32..1024): gates activate.
        // Behavior depends on elapsed time, so just verify it's callable.
        let _ = admit(batch_start, 32, 100);
        let _ = admit(batch_start, 128, 100);
    }

    #[test]
    fn certified_admit_decides_on_cost_not_index() {
        // The discovery, mirrored from value_door: at the SAME index the decision
        // must flip on per-step cost. A CHEAP agent (cost <= coordination) is the
        // RED fast lane — admitted immediately even at a high index where the
        // index-window heuristic would have gated it. A HEAVY agent (cost >
        // coordination) is GREEN and routes through the time corridor.
        let coordination = 200u64;
        let batch_start = Instant::now();

        // Cheap step at a high index → RED → admitted now (index heuristic would
        // have gated it in the 32..1024 sweet zone).
        assert!(
            admit_certified(batch_start, 64, 5, 1, coordination),
            "cheap certified step must be the RED fast lane at any index"
        );

        // Heavy step at index 0 → GREEN → still gated by the corridor, but index 0
        // opens immediately (elapsed >= 0), so admitted.
        assert!(
            admit_certified(batch_start, 0, 5, 5_000, coordination),
            "heavy certified step at index 0 opens immediately"
        );
    }

    #[test]
    fn certified_admit_never_yellow() {
        // certified_light → Light is never Yellow; admit_certified is therefore a
        // total decision over every (cost, coordination) pair. We can only observe
        // the boolean, but the RED branch is unconditionally true and the GREEN
        // branch is the time gate — neither path stalls on a probe.
        let batch_start = Instant::now();
        for cost in [0u64, 1, 100, 200, 201, 10_000] {
            // index 0 ⇒ the GREEN time gate is also open immediately, so every
            // pair admits at index 0: proof there is no YELLOW limbo.
            assert!(admit_certified(batch_start, 0, 5, cost, 200));
        }
    }

    #[test]
    fn test_admit_helix_stagger() {
        let batch_start = Instant::now();
        let service_time_us = 100;

        assert!(admit_helix(batch_start, 0, service_time_us));

        // Request 1 should not admit immediately.
        let first_check = admit_helix(batch_start, 1, service_time_us);
        if first_check {
            return; // System too fast, skip rest.
        }

        // Wait for admission.
        thread::sleep(Duration::from_micros(150));
        assert!(admit_helix(batch_start, 1, service_time_us));
    }
}
